func TestStorageApplySnapshot(t *testing.T) {
	cs := &pb.ConfState{Voters: []uint64{1, 2, 3}}
	data := []byte("data")

	testCases := []struct {
		name          string
		snapshots     []pb.Snapshot
		expectedError error
	}{
		{
			name: "normal case",
			snapshots: []pb.Snapshot{
				{Data: data, Metadata: pb.SnapshotMetadata{Index: 4, Term: 4, ConfState: *cs}},
