func (wal *bootstrappedWAL) MemoryStorage() *raft.InMemoryRaftLog {
	s := raft.NewInMemoryRaftLog()
	if wal.snapshot != nil {
		s.ApplySnapshot(*wal.snapshot)
	}
	if wal.st != nil {
		s.SetHardState(*wal.st)
	}
	if len(wal.ents) != 0 {
		s.Append(wal.ents)
	}
	return s
}

